import base64
from google.cloud import firestore, pubsub_v1

def process_file(event, context):
    bucket_name = event['bucket']
    file_name = event['name']

    # Firestore client
    db = firestore.Client()

    # Pub/Sub client
    publisher = pubsub_v1.PublisherClient()
    topic_path = publisher.topic_path('your-project-id', 'your-topic-id')

    try:
        # Simulate processing the file
        processed_data = f"Processed {file_name} from {bucket_name}"

        # Write to Firestore
        doc_ref = db.collection('processed_files').document(file_name)
        doc_ref.set({'data': processed_data})

        # Publish to Pub/Sub
        data = processed_data.encode('utf-8')
        publisher.publish(topic_path, data)

        print(f"Processed {file_name} and published to Pub/Sub")
    except Exception as e:
        print(f"Error processing file: {e}")